import React, { useEffect, useState } from "react";
import PDFAnalyzer from "./components/PDFAnalyzer";
import "./components/PDFViewer.css";
import "./App.css";



function App() {
  const [pdfs, setPdfs] = useState([]);
  const [selectedPdf, setSelectedPdf] = useState("");
  const [analysisResult, setAnalysisResult] = useState("");

  // Fetch the list of PDFs from the backend
  useEffect(() => {
    fetch("http://localhost:8000/pdfs")
      .then((response) => response.json())
      .then((data) => setPdfs(data.pdfs || []))
      .catch((error) => console.error("Error fetching PDFs:", error));
  }, []);

  const handleAnalyze = (pdf) => {
    setSelectedPdf(pdf); // Set selected PDF
    fetch("http://localhost:8000/analyze-section", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        pdf: pdf, // PDF name sent to backend
        section: "summary", // Example section
        model: "ibm/granite-13b-instruct-v2",
      }),
    })
      .then((response) => response.json())
      .then((data) => {
        setAnalysisResult(data.content); // Show analysis result
      })
      .catch((error) => {
        console.error("Error analyzing PDF:", error);
        setAnalysisResult("An error occurred while analyzing the PDF.");
      });
  };

  return (
    <div className="App">
      <h1>Watsonx APS Application</h1>

      <div>
        <h2>Select an Applicant</h2>
        <select onChange={(e) => handleAnalyze(e.target.value)} value={selectedPdf}>
          <option value="">Select PDF</option>
          {pdfs.map((pdf, index) => (
            <option key={index} value={pdf}>
              {pdf}
            </option>
          ))}
        </select>
      </div>

      <div>
        <h2>Analysis Result</h2>
        <p>{analysisResult}</p>
      </div>
    </div>
  );
}

export default App;
